import { Router } from "express";
import { DeleteProfile, Login, Profile, Register, UpdateProfile } from "./user.controller.js";
import { authenticate } from "../../shared/middleware/Authentication.js";
import { authorizeUserAccess } from "../../shared/middleware/Authorization.js";
const router = Router();
router.post("/register", Register);
router.post("/login", Login);
router.get("/getProfile/:userId", authenticate, authorizeUserAccess(), Profile);
router.put("/update/:userId", authenticate, authorizeUserAccess(), UpdateProfile);
router.delete("/delete/:userId", authenticate, authorizeUserAccess(), DeleteProfile);
export const UserRoutes = router;
